choose.when:
		INSERT ALL
  		  INTO
      		   PLU_USER
       		   (
		       USER_ID
		     , USER_PWD
		     , NICKNAME
		       )
		VALUES
		       (
		       #{user.userId}
		     , #{user.userPwd}
		     , #{user.nickname}
		       )
  		  INTO
      		   PROFILE
       		   (
		       USER_ID
		     , ORIGIN_PROFILE_NAME
		     , CHANGE_PROFILE_NAME
		       )
		VALUES
		       (
		       #{profile.userId}
		     , #{profile.originProfileName}
		     , #{profile.changeProfileName}
		       )				       
		SELECT * FROM DUAL

choose.otherwise:
		INSERT
  		  INTO
      		   PLU_USER
       		   (
		       USER_ID
		     , USER_PWD
		     , NICKNAME
		       )
		VALUES
		       (
		       #{user.userId}
		     , #{user.userPwd}
		     , #{user.nickname}
		       )
